use aiken/fuzz
use cardano/transaction.{Transaction}

/// Net position after matching N buy orders against M sell orders
/// Simplified: single buyer/seller, net_qty = buy_qty - sell_qty
fn net_position(buy_qty: Int, sell_qty: Int) -> Int {
  buy_qty - sell_qty
}

/// Settlement amount for net position at clearing price
fn settlement_amount(net_qty: Int, clearing_price: Int) -> Int {
  if net_qty >= 0 {
    net_qty * clearing_price
  } else {
    -net_qty * clearing_price
  }
}

/// Fully netted position has zero settlement
fn is_fully_netted(buy_qty: Int, sell_qty: Int) -> Bool {
  buy_qty == sell_qty
}

pub type OrderDatum {
  buy_qty: Int
  sell_qty: Int
  clearing_price: Int
  max_settlement: Int
}

pub type OrderRedeemer {
  Settle
  Cancel
}

validator order_netting {
  spend(
    datum: Option<OrderDatum>,
    redeemer: OrderRedeemer,
    _output_ref: Data,
    _self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Cancel -> True
      Settle -> {
        let net = net_position(d.buy_qty, d.sell_qty)
        let amount = settlement_amount(net, d.clearing_price)
        if is_fully_netted(d.buy_qty, d.sell_qty) {
          amount == 0
        } else {
          amount <= d.max_settlement && amount >= 0
        }
      }
    }
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_equal_buys_sells_net_zero(
  qty via fuzz.int_between(1, 1000),
) {
  net_position(qty, qty) == 0 && is_fully_netted(qty, qty)
}

test prop_net_long_positive(
  vals via fuzz.both(fuzz.int_between(101, 1000), fuzz.int_between(1, 100)),
) {
  let (buy, sell) = vals
  net_position(buy, sell) > 0
}

test prop_settlement_zero_when_netted(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  settlement_amount(net_position(qty, qty), price) == 0
}

test prop_settlement_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (net, price) = vals
  settlement_amount(net, price) >= 0
}

use aiken/fuzz
use aiken/interval
use cardano/transaction.{Transaction}

/// Cliff period: no tokens vest before the cliff slot
fn past_cliff(validity_range: interval.Interval, cliff_slot: Int) -> Bool {
  interval.is_entirely_after(validity_range, cliff_slot)
}

/// After cliff: vested amount is proportional to time elapsed
fn vested_after_cliff(
  total_amount: Int,
  elapsed: Int,
  total_period: Int,
) -> Int {
  total_amount * elapsed / total_period
}

// ── Datum / Redeemer ─────────────────────────────────────────────────────────

pub type VestingDatum {
  beneficiary: ByteArray
  cliff_slot: Int
  total_amount: Int
  total_period: Int
  start_slot: Int
}

pub type VestingRedeemer {
  elapsed: Int
  withdraw_amount: Int
}

// ── Validator ────────────────────────────────────────────────────────────────

validator vesting_cliff {
  spend(
    datum: Option<VestingDatum>,
    redeemer: VestingRedeemer,
    _output_reference: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let VestingRedeemer { elapsed, withdraw_amount } = redeemer

    // 1. Cliff must have passed
    let cliff_ok = past_cliff(self.validity_range, d.cliff_slot)

    // 2. Requested amount must not exceed the vested portion
    let vested = vested_after_cliff(d.total_amount, elapsed, d.total_period)
    let amount_ok = withdraw_amount <= vested

    cliff_ok && amount_ok
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_before_cliff_blocked(
  cliff via fuzz.int_between(1001, 2000),
) {
  !past_cliff(interval.before(1000), cliff)
}

test prop_after_cliff_allowed(
  cliff via fuzz.int_between(0, 999),
) {
  past_cliff(interval.after(1000), cliff)
}

test prop_full_period_vests_all(
  total via fuzz.int_between(1, 100000),
) {
  vested_after_cliff(total, 1000, 1000) == total
}

test prop_zero_elapsed_vests_nothing(
  total via fuzz.int_between(1, 100000),
) {
  vested_after_cliff(total, 0, 1000) == 0
}

use aiken/collection/list
use aiken/fuzz
use cardano/transaction.{Transaction}

/// Batch liquidation: process multiple positions, count how many are liquidatable
fn count_liquidatable(
  positions: List<(Int, Int)>,
  threshold: Int,
) -> Int {
  list.foldl(
    positions,
    0,
    fn(pos, acc) {
      let (collateral, debt) = pos
      let hf = collateral * 100 / debt
      if hf < threshold { acc + 1 } else { acc }
    },
  )
}

/// All positions in the batch must be liquidatable
fn all_liquidatable(positions: List<(Int, Int)>, threshold: Int) -> Bool {
  count_liquidatable(positions, threshold) == list.length(positions)
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_undercollateralised_counted(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(101, 200)),
) {
  let (collateral, debt) = vals
  count_liquidatable([(collateral, debt)], 150) == 1
}

test prop_overcollateralised_not_counted(
  vals via fuzz.both(fuzz.int_between(200, 500), fuzz.int_between(1, 100)),
) {
  let (collateral, debt) = vals
  count_liquidatable([(collateral, debt)], 150) == 0
}

test prop_empty_batch_zero_count() {
  count_liquidatable([], 150) == 0
}

test prop_all_liquidatable_batch(
  vals via fuzz.both(fuzz.int_between(1, 50), fuzz.int_between(100, 200)),
) {
  let (collateral, debt) = vals
  all_liquidatable([(collateral, debt), (collateral, debt)], 150)
}

// ── Datum / Redeemer ─────────────────────────────────────────────────────────

pub type LiquidationDatum {
  positions: List<(Int, Int)>
  threshold: Int
}

pub type LiquidationRedeemer {
  min_liquidatable: Int
}

// ── Validator ────────────────────────────────────────────────────────────────

validator liquidation_batch {
  spend(
    datum: Option<LiquidationDatum>,
    redeemer: LiquidationRedeemer,
    _output_reference: Data,
    _self: Transaction,
  ) {
    expect Some(d) = datum
    let liquidatable = count_liquidatable(d.positions, d.threshold)
    let meets_minimum = liquidatable >= redeemer.min_liquidatable
    let batch_fully_liquidatable = all_liquidatable(d.positions, d.threshold)
    meets_minimum && batch_fully_liquidatable
  }

  else(_) {
    fail
  }
}

use aiken/fuzz
use cardano/assets
use cardano/transaction.{Transaction}

/// Liquidation penalty: liquidator pays debt and receives collateral + bonus
fn liquidation_bonus(collateral: Int, bonus_bps: Int) -> Int {
  collateral * bonus_bps / 10000
}

/// Liquidator receives: collateral + bonus
fn liquidator_receives(collateral: Int, bonus_bps: Int) -> Int {
  collateral + liquidation_bonus(collateral, bonus_bps)
}

/// Bonus is non-negative and bounded
fn bonus_in_range(collateral: Int, bonus_bps: Int) -> Bool {
  bonus_bps >= 0 && bonus_bps < 10000
    && liquidation_bonus(collateral, bonus_bps) >= 0
}

pub type LiquidationDatum {
  collateral_lovelace: Int
  bonus_bps: Int
  borrower_pkh: ByteArray
}

pub type LiquidationRedeemer {
  Liquidate
  Reclaim
}

validator liquidation_penalty {
  spend(
    datum: Option<LiquidationDatum>,
    redeemer: LiquidationRedeemer,
    _own_ref: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Reclaim -> {
        let borrower_signed =
          list.any(
            self.extra_signatories,
            fn(pkh) { pkh == d.borrower_pkh },
          )
        borrower_signed
      }
      Liquidate -> {
        let valid_bonus = bonus_in_range(d.collateral_lovelace, d.bonus_bps)
        let expected_out = liquidator_receives(d.collateral_lovelace, d.bonus_bps)
        let total_minted = assets.reduce(self.mint, 0, fn(_p, _n, qty, acc) { acc + qty })
        valid_bonus && expected_out > 0 && total_minted == 0
      }
    }
  }

  else(_) {
    fail
  }
}

