use aiken/fuzz
use cardano/transaction.{Transaction}

/// Partial liquidation: liquidate only enough to restore health
/// Returns minimum debt to repay to reach target_ratio
fn min_repay_to_restore(
  collateral: Int,
  debt: Int,
  target_ratio: Int,
) -> Int {
  // Need: collateral * 100 >= new_debt * target_ratio
  // → new_debt <= collateral * 100 / target_ratio
  // → repay = debt - new_debt
  let max_debt = collateral * 100 / target_ratio
  if debt > max_debt { debt - max_debt } else { 0 }
}

/// After partial repayment, position is healthy
fn healthy_after_repay(
  collateral: Int,
  debt: Int,
  repay: Int,
  target_ratio: Int,
) -> Bool {
  let new_debt = debt - repay
  new_debt > 0 && collateral * 100 >= new_debt * target_ratio
}

// ── Datum / Redeemer types ────────────────────────────────────────────────────

pub type LiquidationDatum {
  collateral: Int
  debt: Int
  target_ratio: Int
}

pub type LiquidationRedeemer {
  repay_amount: Int
}

// ── Validator ────────────────────────────────────────────────────────────────

validator partial_liquidation {
  spend(
    datum: Option<LiquidationDatum>,
    redeemer: LiquidationRedeemer,
    _output_reference: Data,
    _self: Transaction,
  ) {
    expect Some(d) = datum
    let LiquidationRedeemer { repay_amount } = redeemer
    let min_repay =
      min_repay_to_restore(d.collateral, d.debt, d.target_ratio)
    let repay_covers_minimum = repay_amount >= min_repay
    let position_healthy_after =
      healthy_after_repay(d.collateral, d.debt, repay_amount, d.target_ratio)
    repay_covers_minimum && position_healthy_after
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_no_repay_needed_when_healthy(
  vals via fuzz.both(fuzz.int_between(200, 500), fuzz.int_between(1, 100)),
) {
  let (collateral, debt) = vals
  min_repay_to_restore(collateral, debt, 150) == 0
}

test prop_repay_restores_health(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(101, 200)),
) {
  let (collateral, debt) = vals
  let repay = min_repay_to_restore(collateral, debt, 150)
  repay == 0 || healthy_after_repay(collateral, debt, repay, 150)
}

test prop_full_repay_always_healthy(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (collateral, debt) = vals
  // Repay all but 1 lovelace
  let repay = debt - 1
  healthy_after_repay(collateral, debt, repay, 0)
}

test prop_min_repay_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (collateral, debt) = vals
  min_repay_to_restore(collateral, debt, 150) >= 0
}

use aiken/fuzz
use cardano/transaction.{Transaction}

/// Dutch liquidation auction: collateral price starts high and drops over time
/// price = start_price - (start_price - floor_price) * elapsed / duration
fn dutch_liq_price(
  start_price: Int,
  floor_price: Int,
  elapsed:     Int,
  duration:    Int,
) -> Int {
  if elapsed >= duration {
    floor_price
  } else {
    let drop = (start_price - floor_price) * elapsed / duration
    start_price - drop
  }
}

/// Liquidator profit: collateral_value - price_paid - debt_repaid
fn liquidator_profit(
  collateral_value: Int,
  price_paid:       Int,
  debt_repaid:      Int,
) -> Int {
  collateral_value - price_paid - debt_repaid
}

// ── Datum / Redeemer ─────────────────────────────────────────────────────────

pub type AuctionDatum {
  start_price: Int
  floor_price: Int
  duration: Int
  debt_repaid: Int
  collateral_value: Int
}

pub type LiqRedeemer {
  elapsed: Int
  price_paid: Int
}

// ── Validator ────────────────────────────────────────────────────────────────

validator dutch_liquidation {
  spend(
    datum: Option<AuctionDatum>,
    redeemer: LiqRedeemer,
    _output_ref: Data,
    _self: Transaction,
  ) {
    expect Some(d) = datum
    let current_price =
      dutch_liq_price(d.start_price, d.floor_price, redeemer.elapsed, d.duration)
    let price_ok = redeemer.price_paid >= current_price
    let profit =
      liquidator_profit(d.collateral_value, redeemer.price_paid, d.debt_repaid)
    let profitable = profit >= 0
    price_ok && profitable
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_price_starts_at_maximum(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(1, 99)),
) {
  let (start, floor) = vals
  dutch_liq_price(start, floor, 0, 100) == start
}

test prop_price_ends_at_floor(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(1, 99)),
) {
  let (start, floor) = vals
  dutch_liq_price(start, floor, 100, 100) == floor
}

test prop_price_non_increasing(
  vals via fuzz.both(fuzz.int_between(0, 99), fuzz.int_between(1, 99)),
) {
  let (t1, floor) = vals
  dutch_liq_price(100, floor, t1, 100) >= dutch_liq_price(100, floor, t1 + 1, 100)
}

test prop_profit_positive_at_floor(
  vals via fuzz.both(fuzz.int_between(200, 1000), fuzz.int_between(1, 50)),
) {
  let (collateral, debt) = vals
  // Buy at floor=1, repay debt=debt
  liquidator_profit(collateral, 1, debt) > 0
}

use aiken/fuzz
use cardano/transaction.{Transaction}

/// Insurance fund covers bad debt when collateral is insufficient
fn bad_debt(collateral: Int, debt: Int) -> Int {
  if debt > collateral { debt - collateral } else { 0 }
}

/// Insurance fund must cover bad debt
fn insurance_covers(
  collateral: Int,
  debt: Int,
  insurance_fund: Int,
) -> Bool {
  insurance_fund >= bad_debt(collateral, debt)
}

/// After insurance payout, remaining fund
fn remaining_fund(
  collateral: Int,
  debt: Int,
  insurance_fund: Int,
) -> Int {
  insurance_fund - bad_debt(collateral, debt)
}

pub type LiquidationDatum {
  collateral: Int
  debt: Int
  insurance_fund: Int
}

pub type LiquidationRedeemer {
  Liquidate
  Replenish { top_up: Int }
}

validator liquidation_insurance {
  spend(
    datum: Option<LiquidationDatum>,
    redeemer: LiquidationRedeemer,
    _output_ref: Data,
    _self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Liquidate -> {
        let covered = insurance_covers(d.collateral, d.debt, d.insurance_fund)
        let remainder = remaining_fund(d.collateral, d.debt, d.insurance_fund)
        covered && remainder >= 0
      }
      Replenish { top_up } -> {
        let new_fund = d.insurance_fund + top_up
        top_up > 0 && insurance_covers(d.collateral, d.debt, new_fund)
      }
    }
  }

  else(_) {
    fail
  }
}

